let data = $input.first().json;
if (Array.isArray(data) && data.length && typeof data[0] === 'object') {
  data = data[0];
}
if (!data || typeof data !== 'object') data = {};

const wf = data.workflow || {};
const wfName = wf.name || 'Unknown workflow';
const wfId = wf.id != null ? String(wf.id) : '';

let errMsg = '';
let lastNode = '';
let execUrl = '';
let execId = '';
let mode = '';

if (data.execution) {
  const ex = data.execution;
  mode = ex.mode || '';
  lastNode = ex.lastNodeExecuted || '';
  execUrl = ex.url || '';
  execId = ex.id != null ? String(ex.id) : '';
  const err = ex.error;
  if (err && typeof err === 'object') {
    errMsg = err.message || err.description || err.reason || JSON.stringify(err);
  } else if (err) {
    errMsg = String(err);
  }
} else if (data.trigger) {
  const t = data.trigger;
  mode = t.mode || 'trigger';
  const te = t.error || {};
  errMsg = te.message || (te.cause && te.cause.message) || te.name || 'Trigger error';
  lastNode = (te.node && te.node.name) ? te.node.name : 'trigger';
}

if (!errMsg) errMsg = 'Unknown error (no message in payload)';
const msgShort = errMsg.length > 1800 ? errMsg.slice(0, 1800) + '…' : errMsg;

const lines = [
  `n8n workflow failed: *${wfName}*${wfId ? ` (id ${wfId})` : ''}`,
  `Node: ${lastNode || '—'}`,
  `Mode: ${mode || '—'}`,
  `Error: ${msgShort}`
];
if (execUrl) lines.push(`Execution: ${execUrl}`);
else if (execId) lines.push(`Execution id: ${execId}`);

return [{
  json: {
    message: lines.join('\n'),
    priority: 'error',
    _logNotes: msgShort.slice(0, 500),
    _wfName: wfName
  }
}];

let notes = '';
let wfName = 'SYS 00 — Global Error Notification';
try {
  notes = $('Prep Chat Message').first().json._logNotes || '';
  wfName = $('Prep Chat Message').first().json._wfName || wfName;
} catch (e) {}
return [{
  json: {
    workflowName: 'SYS 00 — Global Error Notification',
    contactName: wfName,
    phone: '',
    eventType: 'workflow_error',
    status: 'failure',
    notes: notes || 'workflow_error'
  }
}];
